def lcs_len(a, b):
    # standard dynamic programming
    m, n = len(a), len(b)
    dp = [0]*(n+1)
    for i in range(m):
        prev = 0
        for j in range(n):
            tmp = dp[j+1]
            if a[i] == b[j]:
                dp[j+1] = prev + 1
            else:
                dp[j+1] = max(dp[j+1], dp[j])
            prev = tmp
    return dp[-1]

def lcs_ratio(a,b):
    # normalized LCS: 2*lcs/(len(a)+len(b))
    if len(a)+len(b)==0:
        return 1.0
    l = lcs_len(a,b)
    return 2*l/(len(a)+len(b))

